/** On-device STONE wallets — generated by local bloodstoned, keys never leave the phone. */

import { isCapacitorAndroid } from "./device-fleet.js";
import { isAndroidAppContext, whenCapacitorReady } from "./capacitor-ready.js";
import {
  getLocalNodeStatus,
  localNodePlugin,
  supportsOnDeviceWallet,
} from "./local-node.js";

function onAndroidApp() {
  return isCapacitorAndroid() || isAndroidAppContext();
}

async function walletPluginReady() {
  if (!onAndroidApp()) {
    return null;
  }
  await whenCapacitorReady(15000);
  const plugin = localWalletPlugin();
  if (plugin?.createLocalWallet && plugin?.listLocalWallets) {
    return plugin;
  }
  return null;
}

const PRIMARY_WALLET_KEY = "bloodstone-local-wallet-primary";

export function localWalletPlugin() {
  return localNodePlugin();
}

export function getPrimaryLocalAddress() {
  try {
    return (localStorage.getItem(PRIMARY_WALLET_KEY) || "").trim();
  } catch (_) {
    return "";
  }
}

export function setPrimaryLocalAddress(address) {
  const addr = String(address || "").trim();
  if (!addr) return "";
  try {
    localStorage.setItem(PRIMARY_WALLET_KEY, addr);
  } catch (_) {
    /* ignore */
  }
  return addr;
}

export async function listLocalWallets() {
  const plugin = await walletPluginReady();
  if (!plugin) {
    return { onDevice: onAndroidApp(), nodeRunning: false, entries: [], count: 0 };
  }
  try {
    return await plugin.listLocalWallets();
  } catch (_) {
    return { onDevice: true, nodeRunning: false, entries: [], count: 0 };
  }
}

export async function createLocalWallet(passphrase, label = "mobile") {
  const plugin = await walletPluginReady();
  if (!plugin) {
    if (!onAndroidApp()) {
      throw new Error("On-device wallet is only available in the Android app");
    }
    throw new Error(
      "Wallet bridge not ready — open the app from the home icon (not Chrome), "
      + "then try Updates → Check for updates if this persists.",
    );
  }
  const status = await getLocalNodeStatus();
  if (!status?.running) {
    throw new Error("Start your local node first (Options → local node mode), then create a wallet");
  }
  if (!status?.bloodstonedAlive) {
    throw new Error(
      "bloodstoned is still starting — wait for chain sync progress, then create the wallet",
    );
  }
  if (!supportsOnDeviceWallet(status.mode)) {
    throw new Error(
      `On-device wallet is not available in ${status.mode} mode — use Pruned, Full, or Mesh`,
    );
  }
  const result = await plugin.createLocalWallet({ passphrase, label });
  if (result?.address) {
    setPrimaryLocalAddress(result.address);
  }
  return result;
}

export async function getNewLocalAddress(wallet, passphrase, label = "mobile") {
  const plugin = await walletPluginReady();
  if (!plugin?.getNewLocalAddress) {
    if (!onAndroidApp()) {
      throw new Error("On-device wallet is only available in the Android app");
    }
    throw new Error("Wallet bridge not ready — restart the app and try again.");
  }
  return plugin.getNewLocalAddress({ wallet, passphrase, label });
}

export function initLocalWalletPanel({
  panelId = "local-wallet-panel",
  onAddress = null,
} = {}) {
  if (!isCapacitorAndroid()) return;

  const panel = document.getElementById(panelId);
  if (!panel) return;
  panel.hidden = false;

  const statusEl = document.getElementById("local-wallet-status");
  const listEl = document.getElementById("local-wallet-list");
  const passphraseEl = document.getElementById("local-wallet-passphrase");
  const createBtn = document.getElementById("local-wallet-create-btn");
  const useBtn = document.getElementById("local-wallet-use-btn");
  const primaryEl = document.getElementById("local-wallet-primary");

  async function refresh() {
    const nodeStatus = await getLocalNodeStatus();
    const data = await listLocalWallets();
    const primary = getPrimaryLocalAddress();

    if (statusEl) {
      if (!nodeStatus?.running) {
        statusEl.textContent =
          "Local node offline — start it to create wallets on this phone (keys never leave the device).";
      } else if (!nodeStatus?.bloodstonedAlive) {
        statusEl.textContent =
          "bloodstoned is starting — wait for sync progress before creating a wallet.";
      } else if (!supportsOnDeviceWallet(nodeStatus.mode)) {
        statusEl.textContent =
          `Wallet not available in ${nodeStatus.mode} mode — switch to Pruned, Full, or Mesh.`;
      } else {
        statusEl.textContent =
          "Node running — wallets are stored in your phone's private app data (wallet.dat on-device).";
      }
    }
    if (primaryEl) {
      primaryEl.textContent = primary || "—";
    }
    if (listEl) {
      const entries = data?.entries || [];
      if (!entries.length) {
        listEl.innerHTML = "<p class=\"muted small\">No on-device wallets yet.</p>";
      } else {
        listEl.innerHTML = entries
          .map(
            (row) =>
              `<div class="mono small" style="margin:0.35rem 0">` +
              `<strong>${row.address}</strong><br>` +
              `<span class="muted">wallet ${row.wallet || "—"}</span></div>`
          )
          .join("");
      }
    }
    if (createBtn) {
      createBtn.disabled = !(
        nodeStatus?.running
        && nodeStatus?.bloodstonedAlive
        && supportsOnDeviceWallet(nodeStatus.mode)
      );
    }
  }

  if (createBtn) {
    createBtn.addEventListener("click", async () => {
      const pass = (passphraseEl?.value || "").trim();
      if (pass.length < 8) {
        alert("Choose a passphrase of at least 8 characters (stored only on this phone).");
        return;
      }
      createBtn.disabled = true;
      try {
        const result = await createLocalWallet(pass);
        if (passphraseEl) passphraseEl.value = "";
        if (statusEl) {
          statusEl.textContent = `Created ${result.address} — private keys stay on this device.`;
        }
        if (typeof onAddress === "function") {
          onAddress(result.address);
        }
        await refresh();
      } catch (err) {
        alert(err?.message || String(err));
      } finally {
        createBtn.disabled = false;
        await refresh();
      }
    });
  }

  if (useBtn) {
    useBtn.addEventListener("click", () => {
      const primary = getPrimaryLocalAddress();
      if (!primary) {
        alert("Create an on-device wallet first.");
        return;
      }
      if (typeof onAddress === "function") {
        onAddress(primary);
      }
    });
  }

  refresh();
  setInterval(refresh, 30000);
}